SELECT COUNT(*) AS QUANTIDADE FROM SERVIDOR_PROJ SP JOIN PROJ P ON P.PK = SP.FK_PROJ JOIN SERVIDOR S ON S.PK_SIAPE = SP.FK_SIAPE WHERE LOWER(S.GENERO) = LOWER('feminino') AND LOWER(S.SIGLA_CAMPUS) = LOWER('for') AND LOWER(SP.PAPEL) = LOWER('autor') AND LOWER(P.TIPO_PROJETO) = LOWER('pesquisa') AND LOWER(P.AREA_CONHECIMENTO) LIKE LOWER('%biologia geral%') AND P.DATA_INICIO >= (DATE('now', '-5 years'))